solution: class Solution {
public:
    int maxScore(string s) {
        int zeros = 0, ones = 0;
        for (char c : s) ones += (c == '1');
        int maxScore = 0;
        for (int i = 0; i < s.size() - 1; ++i) {
            if (s[i] == '0') ++zeros;
            else --ones;
            maxScore = max(maxScore, zeros + ones);
        }
        return maxScore;
    }
};
